let content = '';
const inputData = $input.first().json;

if (inputData.message && inputData.message.content) { 
    content = inputData.message.content; 
} else if (inputData.content) { 
    content = inputData.content; 
} else if (inputData.choices && inputData.choices[0] && inputData.choices[0].message) { 
    content = inputData.choices[0].message.content; 
}

let cleanText = content.trim();
const bt = String.fromCharCode(96, 96, 96);

if (cleanText.startsWith(bt)) {
    let lines = cleanText.split('\n');
    lines.shift(); 
    if (lines[lines.length - 1].startsWith(bt)) {
        lines.pop(); 
    }
    cleanText = lines.join('\n').trim();
}

let result = { scenes: [] };

try {
    let parsed = JSON.parse(cleanText);
    if (Array.isArray(parsed)) {
        result.scenes = parsed;
    } else if (parsed.scenes) {
        result.scenes = parsed.scenes;
    } else {
        result.scenes = [parsed];
    }
} catch (e) {
    result.scenes = [ { image_prompt: cleanText, video_prompt: cleanText, aiModel: 'auto', duration: 5, useEndFrame: false } ];
}

return { 
    json: { 
        scenes: result.scenes 
    } 
};

const errorData = $json;

let clientId = '00000000-0000-0000-0000-000000000000';
let postId   = null;
let amount   = 0;
let errorMsg = 'Unknown error';

try {
  const runData =
    errorData?.data?.resultData?.runData ||
    errorData?.execution?.data?.resultData?.runData ||
    {};

  const parseNames = ['Parse Inputs & Calculate Cost', 'Parse Input', 'Parse Inputs'];
  for (const name of parseNames) {
    const nodeRuns = runData[name];
    if (nodeRuns?.[0]?.data?.main?.[0]?.[0]?.json) {
      const d = nodeRuns[0].data.main[0][0].json;
      clientId = String(d.clientId || d.client_id || clientId);
      postId   = d.postId   || d.post_id   || postId;
      amount   = Number(d.totalCost || d.cost || d.amount || amount);
      break;
    }
  }

  if (clientId === '00000000-0000-0000-0000-000000000000') {
    const webhookNames = Object.keys(runData).filter(n => n.toLowerCase().includes('webhook'));
    for (const name of webhookNames) {
      const nodeRuns = runData[name];
      if (nodeRuns?.[0]?.data?.main?.[0]?.[0]?.json) {
        const body = nodeRuns[0].data.main[0][0].json?.body || nodeRuns[0].data.main[0][0].json;
        clientId = String(body.client_id || body.clientId || clientId);
        postId   = postId || body.post_id || body.postId || null;
        break;
      }
    }
  }

  errorMsg = errorData?.error?.message ||
             errorData?.execution?.error?.message ||
             errorData?.lastNodeExecuted || 'Unknown';
} catch(e) { }

return [{ json: {
  clientId,
  postId,
  amount,
  canRefund: clientId !== '00000000-0000-0000-0000-000000000000',
  canMarkFailed: !!postId,
  errorNode:    errorData?.lastNodeExecuted || errorData?.execution?.lastNodeExecuted || 'unknown',
  errorMessage: errorMsg
} }];
